import { IMessageEvent, MessageEvent } from '@nitrots/nitro-renderer/src/core';
import { TradeUpdateParser } from '@nitrots/nitro-renderer/src/nitro/communication/messages/parser/TradeUpdateParser';

export class TradeUpdateEvent extends MessageEvent implements IMessageEvent
{
constructor(callback: Function)
{
super(callback, TradeUpdateParser);
}

public getParser(): TradeUpdateParser
{
return this.parser as TradeUpdateParser;
}
}